  38 |         :root {
  39 |             --bg: #050505;
  40 |             --card-bg: #151517;
  41 |             --input-bg: #0a0a0a;
  42 |             --primary: #3b82f6;
  43 |             --primary-dim: rgba(59, 130, 246, 0.1);
  44 |             --ai-accent: #d946ef;
  45 |             --dev: #eab308;
  46 |             --prod: #22c55e;
  47 |             --danger: #ef4444;
