 274 |         .log-header.expanded { z-index: 60; }
 275 |         .log-header:active { background: #222; }
 276 |         .log-header.expanded { 
 277 |             background: #1e1e20; border-bottom: 1px solid #333; 
 278 |             border-left-color: var(--primary); 
 279 |         }
 280 |         
 281 |         .log-meta { display: flex; align-items: center; gap: 10px; font-size: 12px; flex: 1; }
 282 |         .log-time { color: var(--text-muted); }
 283 |         .log-header .chevron { transition: transform 0.2s ease; color: #666; }
 284 |         .log-header.expanded .chevron { transform: rotate(90deg); }
 285 |         .status-pill { padding: 2px 6px; border-radius: 4px; font-size: 10px; font-weight: bold; text-transform: uppercase; }
 286 |         .pill-success { background: rgba(34, 197, 94, 0.2); color: var(--prod); }
 287 |         .pill-fail { background: rgba(239, 68, 68, 0.2); color: var(--danger); }
 288 |         .log-body { display: none; padding: 0; }
 289 |         .log-body.open { display: block; }
