5194 |     function formatBytes(bytes) {
5195 |         if (!bytes) return '0 B';
5196 |         const k = 1024;
5197 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5198 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5199 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
