7953 |     function convertToCSV(resultObj) {
7954 |         const data = resultObj.data || [];
7955 |         if (!data.length) return '';
7956 |         
7957 |         const tables = extractTableNames(resultObj.sql);
7958 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7959 | 
7960 |         const headers = Object.keys(data[0]);
7961 |         const rows = data.map(row => 
7962 |             headers.map(header => {
7963 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7964 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7965 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7966 |             }).join(',')
7967 |         );
7968 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7969 |     }
