5193 |     function formatBytes(bytes) {
5194 |         if (!bytes) return '0 B';
5195 |         const k = 1024;
5196 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5197 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5198 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5199 |     }
