5201 |     function timeAgo(dateString) {
5202 |         const date = new Date(dateString);
5203 |         const now = new Date();
5204 |         const seconds = Math.floor((now - date) / 1000);
5205 |         if (seconds < 10) return 'just now';
5206 |         if (seconds < 60) return seconds + 's ago';
5207 |         const minutes = Math.floor(seconds / 60);
5208 |         if (minutes < 60) return minutes + 'm ago';
5209 |         const hours = Math.floor(minutes / 60);
5210 |         if (hours < 24) return hours + 'h ago';
5211 |         return date.toLocaleDateString();
5212 |     }
