7952 |     function convertToCSV(resultObj) {
7953 |         const data = resultObj.data || [];
7954 |         if (!data.length) return '';
7955 |         
7956 |         const tables = extractTableNames(resultObj.sql);
7957 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7958 | 
7959 |         const headers = Object.keys(data[0]);
7960 |         const rows = data.map(row => 
7961 |             headers.map(header => {
7962 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7963 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7964 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7965 |             }).join(',')
7966 |         );
7967 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7968 |     }
