        .filter-pill-container::-webkit-scrollbar { display: none; }
        .filter-pill { flex-shrink: 0; padding: 4px 10px; border-radius: 20px; background: #1a1a1c; border: 1px solid var(--border); font-size: 10px; color: var(--text-muted); display: flex; align-items: center; gap: 6px; }
        .filter-pill.active { border-color: var(--ai-accent); color: var(--ai-accent); background: rgba(217, 70, 239, 0.05); }
        .filter-checkbox-item { display: flex; align-items: center; gap: 10px; padding: 12px; border-bottom: 1px solid #222; cursor: pointer; }
        .filter-checkbox-item:last-child { border-bottom: none; }
        .filter-checkbox-item span { font-family: 'JetBrains Mono'; font-size: 12px; flex: 1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
        .model-item {
            display: flex; align-items: center; justify-content: space-between;
            padding: 12px; border-bottom: 1px solid var(--border); transition: background 0.2s;
        }
        .model-item:hover { background: #1a1a1c; }
        .model-item .model-id { font-family: 'JetBrains Mono'; font-size: 12px; color: #eee; flex: 1; }
        .model-item .model-actions { display: flex; gap: 8px; }

        :root {
            --bg: #050505;
            --card-bg: #151517;
            --input-bg: #0a0a0a;
            --primary: #3b82f6;
            --primary-dim: rgba(59, 130, 246, 0.1);
            --ai-accent: #d946ef;
            --dev: #eab308;
            --prod: #22c55e;
            --danger: #ef4444;
            --text-main: #ffffff;
            --text-muted: #a1a1aa;
            --border: #27272a;
            --nav-height: 80px;
        }

        * { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }

        body {
            margin: 0; padding: 0; height: 100vh;
            background-color: var(--bg); color: var(--text-main);
            font-family: 'Inter', sans-serif;
            display: flex; flex-direction: column;
            overflow: hidden;
        }

        .hidden { display: none !important; }
        .flex-between { display: flex; justify-content: space-between; align-items: center; }
        .flex-gap { display: flex; gap: 8px; }

        /* MAIN VIEW LAYOUT */
        .main-view {
            flex: 1; overflow-y: auto; padding: 20px;
            padding-top: calc(env(safe-area-inset-top, 0px) + 20px);
            padding-bottom: calc(var(--nav-height) + 40px);
            scrollbar-width: none;
            scroll-behavior: smooth;
            -webkit-overflow-scrolling: touch;
        }
        /* Safe space for the bottom navigation and FAB */
        .bottom-spacer {
            height: calc(var(--nav-height) + 100px);
            width: 100%;
            flex-shrink: 0;
        }
        .main-view::-webkit-scrollbar { display: none; }

        .tab-content { display: none; animation: fadeUp 0.2s ease-out; }
        .tab-content.active { display: block; }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(5px); } to { opacity: 1; transform: translateY(0); } }

        .header { font-size: 24px; font-weight: 700; margin-bottom: 20px; display: flex; align-items: center; justify-content: space-between; flex-shrink: 0; }

        .card {
            background: var(--card-bg); border: 1px solid var(--border);
            border-radius: 16px; padding: 16px; margin-bottom: 16px;
        }

        /* BUTTONS */
        .btn {
            width: 100%; padding: 14px; border-radius: 12px; border: none;
            font-weight: 600; font-size: 15px; cursor: pointer;
            display: flex; align-items: center; justify-content: center; gap: 8px;
            color: white; transition: opacity 0.2s;
        }
        .btn:active { opacity: 0.7; }
        .btn-primary { background: var(--primary); }
        .btn-dev { background: var(--dev); color: black; }
        .btn-prod { background: var(--prod); }
        .btn-danger { background: var(--danger); }
        .btn-outline { background: transparent; border: 1px solid var(--border); color: var(--text-muted); }

        /* INPUTS */
        .input-group { margin-bottom: 16px; }
        .input-label { display: block; color: var(--text-muted); font-size: 11px; margin-bottom: 6px; text-transform: uppercase; letter-spacing: 0.5px; }
        .input-field {
            width: 100%; background: var(--input-bg); border: 1px solid var(--border);
            color: var(--text-main); padding: 12px; border-radius: 10px;
            font-family: 'JetBrains Mono', monospace; font-size: 13px;
        }
        .input-field:focus { outline: 2px solid var(--primary); border-color: transparent; }

        /* FILE LIST */
        .file-list { display: flex; flex-direction: column; gap: 0; }
        .file-item {
            display: flex; justify-content: space-between; align-items: center;
            padding: 12px; border-bottom: 1px solid var(--border);
        }
        .file-item:last-child { border-bottom: none; }

        /* VERSIONS / HISTORY */
        .version-item { position: relative; padding: 12px 0; border-bottom: 1px solid var(--border); }
        .version-item:last-child { border-bottom: none; }
        .v-header { display: flex; justify-content: space-between; align-items: flex-start; }
        .v-info strong { display: block; font-size: 14px; margin-bottom: 2px; }
        .v-info small { color: var(--text-muted); font-size: 11px; }
        .v-note {
            margin-top: 8px; background: rgba(255,255,255,0.05); 
            padding: 8px; border-radius: 6px; font-size: 11px; color: #ddd;
            border-left: 2px solid var(--primary); display: none; cursor: pointer;
        }
        .v-note.has-content { display: block; }

        /* INSPECTOR STYLES */
        .ins-row { padding: 8px 12px; border-bottom: 1px solid #1a1a1c; font-family: 'JetBrains Mono'; font-size: 11px; position: relative; animation: fadeUp 0.1s; display: flex; align-items: flex-start; }
.ins-row details summary::-webkit-details-marker { color: var(--ai-accent); margin-top: 3px; }
.ins-row details[open] summary { border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 4px; margin-bottom: 4px; }
        .ins-row:hover .ins-copy-btn { opacity: 1; }
        .ins-copy-btn { position: absolute; right: 8px; top: 8px; opacity: 0; background: #222; border: 1px solid #444; color: #888; padding: 2px 6px; border-radius: 4px; cursor: pointer; z-index: 10; }
        .ins-copy-btn:hover { color: white; border-color: var(--primary); }

        .ins-log-info { border-left: 3px solid var(--primary); }
        .ins-log-warn { border-left: 3px solid var(--dev); background: rgba(234, 179, 8, 0.05); }
        .ins-log-error { border-left: 3px solid var(--danger); background: rgba(239, 68, 68, 0.05); }

        .ins-net-grid { display: grid; grid-template-columns: 50px 45px 1fr 60px; gap: 8px; cursor: pointer; align-items: center; }
        .ins-net-details { background: #050505; margin: 8px -12px -8px -12px; padding: 12px; border-top: 1px solid #222; display: none; }
