5202 |         const seconds = Math.floor((now - date) / 1000);
5203 |         if (seconds < 10) return 'just now';
5204 |         if (seconds < 60) return seconds + 's ago';
5205 |         const minutes = Math.floor(seconds / 60);
5206 |         if (minutes < 60) return minutes + 'm ago';
5207 |         const hours = Math.floor(minutes / 60);
5208 |         if (hours < 24) return hours + 'h ago';
5209 |         return date.toLocaleDateString();
