7922 |     function extractTableNames(sql) {
7923 |         if (!sql) return [];
7924 |         const tables = [];
7925 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7926 |         
7927 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7928 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7929 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7930 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7931 | 
7932 |         let match;
7933 |         while ((match = fromRegex.exec(sql)) !== null) {
7934 |             const name = match[1];
7935 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7936 |                 tables.push(name);
7937 |             }
7938 |         }
7939 |         
7940 |         while ((match = metaRegex.exec(sql)) !== null) {
7941 |             const name = match[1];
7942 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7943 |                 tables.push(name);
7944 |             }
7945 |         }
7946 | 
7947 |         return tables;
7948 |     }
7949 | 
7950 |     function convertToCSV(resultObj) {
7951 |         const data = resultObj.data || [];
7952 |         if (!data.length) return '';
7953 |         
7954 |         const tables = extractTableNames(resultObj.sql);
7955 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7956 | 
7957 |         const headers = Object.keys(data[0]);
7958 |         const rows = data.map(row => 
7959 |             headers.map(header => {
7960 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7961 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7962 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7963 |             }).join(',')
7964 |         );
7965 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7966 |     }
