5188 |     function formatBytes(bytes) {
5189 |         if (!bytes) return '0 B';
5190 |         const k = 1024;
5191 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5192 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5193 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5194 |     }
