5196 |     function timeAgo(dateString) {
5197 |         const date = new Date(dateString);
5198 |         const now = new Date();
5199 |         const seconds = Math.floor((now - date) / 1000);
5200 |         if (seconds < 10) return 'just now';
5201 |         if (seconds < 60) return seconds + 's ago';
5202 |         const minutes = Math.floor(seconds / 60);
5203 |         if (minutes < 60) return minutes + 'm ago';
5204 |         const hours = Math.floor(minutes / 60);
5205 |         if (hours < 24) return hours + 'h ago';
5206 |         return date.toLocaleDateString();
5207 |     }
